2253	\begin{lemma}[B2 — source-span flatness descent for section modules]
2254	  \label{lem:gf_section_span_flat_descent}
2255	  \lean{AlgebraicGeometry.gf_section_span_flat_descent}
2256	  \uses{lem:qcoh_section_localization_basicOpen, lem:mathlib_flat_of_isLocalized_span}
2257	  Let \(p : X \to S\) be a morphism, \(\F\) a quasi-coherent \(\OO_X\)-module, \(U\) an open
2258	  of \(S\), and \(W \le p^{-1}(U)\) an affine open of \(X\); give \(\Gamma(\F, W)\) its
2259	  \(\Gamma(S, U)\)-module structure through the restriction
2260	  \(\Gamma(S, U) \to \Gamma(X, W)\). Suppose a finite family \(t \subseteq \Gamma(X, W)\)
2261	  spans the unit ideal, \(\mathrm{Ideal.span}\,t = \top\), and that for each \(g \in t\) the
2262	  basic-open section module \(\Gamma(\F, D(g))\) — the away-localization of
2263	  \(\Gamma(\F, W)\) at \(g\) — is flat over \(\Gamma(S, U)\). Then \(\Gamma(\F, W)\) is flat
2264	  over \(\Gamma(S, U)\).
2265	\end{lemma}
